svg.script:
(function () {
  "use strict";

  var startFrame = document.getElementById("startFrame");
  var endFrame = document.getElementById("endFrame");
  var towerMain = document.getElementById("towerMain");
  var towerDepth = document.getElementById("towerDepth");
  var knob = document.getElementById("knob");
  var trackHit = document.getElementById("trackHit");
  var btnBack = document.getElementById("btnBack");
  var btnPlay = document.getElementById("btnPlay");
  var playIcon = document.getElementById("playIcon");
  var pauseIcon = document.getElementById("pauseIcon");

  var trackMin = 535;
  var trackMax = 1000;
  var progress = 0;
  var dragging = false;
  var playing = false;
  var animationStart = 0;
  var animationFrom = 0;
  var animationDuration = 5200;
  var rafId = 0;

  function clamp(value, min, max) {
    return Math.max(min, Math.min(max, value));
  }

  function lerp(start, end, amount) {
    return start + (end - start) * amount;
  }

  function smoothstep(value) {
    return value * value * (3 - 2 * value);
  }

  function easeInOut(value) {
    return value < 0.5
      ? 4 * value * value * value
      : 1 - Math.pow(-2 * value + 2, 3) / 2;
  }

  function setUseBox(node, x, y, width, height) {
    node.setAttribute("x", x.toFixed(2));
    node.setAttribute("y", y.toFixed(2));
    node.setAttribute("width", width.toFixed(2));
    node.setAttribute("height", height.toFixed(2));
  }

  function render() {
    var eased = smoothstep(progress);
    var towerEase = easeInOut(progress);

    startFrame.setAttribute("opacity", (1 - eased).toFixed(4));
    endFrame.setAttribute("opacity", eased.toFixed(4));

    startFrame.setAttribute(
      "transform",
      "translate(" + (-18 * towerEase).toFixed(2) + " " + (4 * towerEase).toFixed(2) + ") " +
      "scale(" + (1 + 0.018 * towerEase).toFixed(5) + ")"
    );

    endFrame.setAttribute(
      "transform",
      "translate(" + (30 * (1 - towerEase)).toFixed(2) + " " + (-5 * (1 - towerEase)).toFixed(2) + ") " +
      "scale(" + (1 + 0.025 * (1 - towerEase)).toFixed(5) + ")"
    );

    var towerX = lerp(230, 235, towerEase);
    var towerY = lerp(40, 62, towerEase);
    var towerWidth = lerp(200, 126, towerEase);
    var towerHeight = lerp(300, 360, towerEase);
    var towerSkew = lerp(0, -4.5, towerEase);
    var towerLean = lerp(0, -1.8, towerEase);
    var depthOffset = lerp(0, 15, towerEase);

    setUseBox(towerMain, towerX, towerY, towerWidth, towerHeight);
    setUseBox(towerDepth, towerX + depthOffset, towerY + 2, towerWidth, towerHeight);

    towerMain.setAttribute(
      "transform",
      "rotate(" + towerLean.toFixed(2) + " " + (towerX + towerWidth / 2).toFixed(2) + " " + (towerY + towerHeight).toFixed(2) + ") " +
      "skewX(" + towerSkew.toFixed(2) + ")"
    );

    towerDepth.setAttribute(
      "transform",
      "rotate(" + (towerLean - 0.7).toFixed(2) + " " + (towerX + towerWidth / 2).toFixed(2) + " " + (towerY + towerHeight).toFixed(2) + ") " +
      "skewX(" + (towerSkew - 1.5).toFixed(2) + ")"
    );
    towerDepth.setAttribute("opacity", (0.34 * towerEase).toFixed(3));

    knob.setAttribute("cx", (trackMin + progress * (trackMax - trackMin)).toFixed(2));
  }

  function setProgress(nextProgress, stopPlayback) {
    progress = clamp(nextProgress, 0, 1);
    if (stopPlayback) {
      stop();
    }
    render();
  }

  function updatePlayIcon() {
    playIcon.setAttribute("opacity", playing ? "0" : "1");
    pauseIcon.setAttribute("opacity", playing ? "1" : "0");
  }

  function stop() {
    playing = false;
    if (rafId) {
      cancelAnimationFrame(rafId);
      rafId = 0;
    }
    updatePlayIcon();
  }

  function tick(timestamp) {
    if (!playing) {
      return;
    }

    var elapsed = timestamp - animationStart;
    var remaining = 1 - animationFrom;
    var normalized = clamp(elapsed / (animationDuration * Math.max(remaining, 0.08)), 0, 1);
    progress = animationFrom + remaining * easeInOut(normalized);
    render();

    if (normalized >= 1) {
      stop();
      return;
    }

    rafId = requestAnimationFrame(tick);
  }

  function play() {
    if (progress >= 0.999) {
      progress = 0;
    }
    playing = true;
    animationFrom = progress;
    animationStart = performance.now();
    updatePlayIcon();
    rafId = requestAnimationFrame(tick);
  }

  function togglePlay() {
    if (playing) {
      stop();
    } else {
      play();
    }
  }

  function localX(event) {
    var clientX;
    if (event.touches && event.touches.length) {
      clientX = event.touches[0].clientX;
    } else if (event.changedTouches && event.changedTouches.length) {
      clientX = event.changedTouches[0].clientX;
    } else {
      clientX = event.clientX;
    }

    var point = document.documentElement.createSVGPoint();
    point.x = clientX;
    point.y = 0;
    var matrix = document.documentElement.getScreenCTM();
    return matrix ? point.matrixTransform(matrix.inverse()).x : clientX;
  }

  function scrub(event) {
    var x = clamp(localX(event), trackMin, trackMax);
    setProgress((x - trackMin) / (trackMax - trackMin), true);
    event.preventDefault();
  }

  function startDrag(event) {
    dragging = true;
    scrub(event);
  }

  function moveDrag(event) {
    if (!dragging) {
      return;
    }
    scrub(event);
  }

  function endDrag() {
    dragging = false;
  }

  knob.addEventListener("mousedown", startDrag);
  knob.addEventListener("touchstart", startDrag, { passive: false });
  trackHit.addEventListener("mousedown", startDrag);
  trackHit.addEventListener("touchstart", startDrag, { passive: false });

  document.addEventListener("mousemove", moveDrag);
  document.addEventListener("touchmove", moveDrag, { passive: false });
  document.addEventListener("mouseup", endDrag);
  document.addEventListener("touchend", endDrag);
  document.addEventListener("touchcancel", endDrag);

  btnBack.addEventListener("click", function () {
    setProgress(progress - 0.12, true);
  });

  btnPlay.addEventListener("click", togglePlay);

  window.setMountainTurnProgress = function (value) {
    setProgress(Number(value) || 0, true);
  };

  render();

  var reducedMotion = window.matchMedia &&
    window.matchMedia("(prefers-reduced-motion: reduce)").matches;

  if (!reducedMotion) {
    window.setTimeout(play, 450);
  }
})();
